var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"크르르르르…….","JPN":"グルルルル……","ENG":"Grrrrr...","TWN":"嗚喔喔喔喔……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_05"},{"id":"L4_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"날 찾아온다면, 당연히 자랑스러운 조국에서 보낸 녀석들일 줄 알았는데.","JPN":"誰か面と向かいにくるんなら、クソ誇らしい祖国からだろうと思ってたけど。","ENG":"Honestly, if someone came to hunt me down, I figured it'd be someone sent from my proud homeland.","TWN":"如果來找我的話，我以為肯定是我那自豪的祖國派來的人呢。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"근데 이거 어쩌나? 침식체랑 나뒹구는 건 내 취향이 아닌 걸?","JPN":"残念だったな。こっちは侵食体と喧嘩なんて好みじゃないんだ。","ENG":"But sorry to say, messing around with a C.O. isn't really my thing.","TWN":"但是這個怎麼辦？我可不喜歡和侵蝕體糾纏在一起。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"우리도 네게 볼 일 없다. 녹색 머리 여자.","JPN":"オレタチモ、オマエニ用ハナイ。緑ノ髪ノ女。","ENG":"We don't have any business with you, green-haired woman.","TWN":"我們也不想見你，綠頭髮的女人。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐, 뭐라고?","JPN":"な、なんだと？","ENG":"W-what?","TWN":"什，什麼？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"우리가 찾는 것은. 그리운 근원. 모든 것의 고향.","JPN":"オレタチガ探シテイルノハ、懐カシイ根源。全テノ故郷。","ENG":"What we're searching for. The origin. Home of everything.","TWN":"我們尋找的是——懷念的根源，一切的故鄉。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"너와 함께 있던 덩치 작은 여자. 지금 어디 있지?","JPN":"オマエト共ニイタ小サイ女。ドコニイル？","ENG":"The small girl who was with you. Where is she now?","TWN":"和你在一起的那個小個子女人，現在在哪裡？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"나랑 같이 다니는 덩치 작은 녀석?","JPN":"私と共にいた小さいやつ？","ENG":"The small girl I was with?","TWN":"跟我一起走的小個子？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"펠리세트가 뭐 어쨌다고? 침식체가 걔를 왜 찾아? 걔 쥐뿔도 없는데?","JPN":"フェリセットのことか？　侵食体があいつに何の用がある？　あいつは大したやつじゃないぞ？","ENG":"You mean Félicette? What do you want with her? She's not special or anything?","TWN":"費莉塞特怎麼了？侵蝕體為什麼找她？她什麼都沒有啊？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"인간의 이름. 인간의 기준. 그런 건 모른다.","JPN":"人間ノ名前。人間ノ基準。ソンナコトハ知ラナイ。","ENG":"Human name. Human standards. I don't know.","TWN":"人類的名字，人類的標準，這些我都不知道。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"덩치가 작은 여자. 나무로부터 내려온 존재…….","JPN":"小サイ女。木ヨリ送ラレタ存在……","ENG":"Small girl. Descended from the tree...","TWN":"身材嬌小的女子。從樹上降臨的存在……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"나 참, 침식체 주제에 아주 게을러 빠졌구만?","JPN":"ったく、侵食体のくせに怠けやがって。","ENG":"Unbelievable. For a C.O., you're pretty lazy, huh?","TWN":"哎呀，作為侵蝕體竟然這麼懶惰？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이름도 모르면서 누가 누굴 찾는다는 거야, 이 멍청아!","JPN":"名前も知らずに人探しなんかできるもんか、バカ！","ENG":"You don't even know her name. How do you expect to find her, you idiot?","TWN":"連名字都不知道，誰找誰啊，你這個笨蛋！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"동포를 통해서. 정보를 전달받았다.","JPN":"仲間ガ、情報ヲクレタ。","ENG":"Through my kind. Received information.","TWN":"透過同胞，收到了資訊。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"너희 셋. 계속 함께였다. 그러니까 알 수 있다.","JPN":"オマエタチ3人。ズット一緒ダッタ。ダカラワカル。","ENG":"You three. Always together. So we know.","TWN":"你們三個，一直在一起，所以能知道。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"잠깐, 셋이라고?","JPN":"待て、3人だと？","ENG":"Wait, three?","TWN":"等等，三個……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어디보자… 나랑 꼬맹이랑, 스키너…….","JPN":"どれ……私とおこちゃまと、スキナー……","ENG":"Let's see... There's me, little kid, and Skinner...","TWN":"讓我看看……我和小鬼，還有史金納……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아니다. 선수니까 미나까지 포함인가? 그런데 걔 덩치가 작지는……","JPN":"いや、選手だからミナも含めてか？　でもあいつは別に小柄じゃ……","ENG":"Or maybe I should count Mina too? But she's not exactly small...","TWN":"不是。因為是選手，所以也包括米娜嗎？不過她的體型也不小……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Wait what?","TWN":"咦？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"기본 포지션은 최소 한 명씩 들어가는 게 엔트리의 기본 규칙이거든.","JPN":"基本的に、ポジションごとに最低1名ずつ入るのがエントリーの条件でね。","ENG":"The rules for participation require that we have at least one of each position.","TWN":"因為參賽的基本規則，是每個基本位置上都至少要有一個人啦。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"디펜더는 여기 사이코 꼬맹이, 그리고 레인저는 나.","JPN":"ディフェンダーはこっちのサイコガキ、それにレンジャーは私。","ENG":"Psycho kid here's our defender, and I'm the ranger.","TWN":"護衛是這個小瘋子，突擊隊員是我。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"서포터는 스키너가 있으니까 제외. 타워랑 시즈는 예외.","JPN":"サポーターはスキナーがいるからいいとして。タワーとシージは例外。","ENG":"For our supporter, we have Skinner. Towers and sieges are not mandatory.","TWN":"輔助有史金納，所以不算，要塞和攻城也不是必須的。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"남은 건 후방 교란을 맡을 스트라이커랑…. 저격수란 뜻이지.","JPN":"残りは後方を攪乱させるストライカーと……スナイパーなんだ。","ENG":"So all that remains is a striker who can flank behind enemy lines... and a sniper.","TWN":"剩下的就是負責擾亂敵人後方的前鋒和……狙擊手。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그래서 입사하자마자 염치 없는 부탁이긴 한데요.","JPN":"それで入社そうそうに申し訳ないんですけど。","ENG":"And I know I'm asking a lot as soon as I joined the company, but...","TWN":"所以剛入職就要厚著臉皮請公司幫忙。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"저격수 한 명 소개해 주실 수 없을까요, 사장님?","JPN":"スナイパーを1人紹介していただけませんか？　社長。","ENG":"Boss, could you introduce us to a sniper?","TWN":"老闆能幫我們介紹一名狙擊手嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"제 지인들은 다들 소속이 있거든요. 프리랜서를 구하자니 몸값도 비싸고요.","JPN":"私の知り合いはみんなどこかに所属してしまっていて。フリーランサーを雇うのにも大金が要りますし。","ENG":"All my friends are in different teams, and hiring a freelancer is going to be expensive.","TWN":"我認識的朋友都有隸屬的小隊，本來想找自由工作者，但是價格太貴。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"마침 자네들에게 아주 좋은 인재가 있지.","JPN":"ちょうど君たちにぴったりの人材がいる。","ENG":"I have just the person you're looking for.","TWN":"我正好認識一個非常適合你們的人才。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"정말요?","JPN":"本当ですか？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……샤오린이라고 하던가요?","JPN":"……シャオリンでしたっけ？","ENG":"...Are you talking about Xiao Lin?","TWN":"……你是在說曉琳嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그 사람이 아니어도 괜찮아요. 엔트리만 채우면 되니까.","JPN":"あの人じゃなくてもいいです。エントリーだけしてくれればいいので。","ENG":"It doesn't have to be her. We just need someone to fill the spot.","TWN":"不是她也沒關係，我們只需要補足參賽人員就行。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"INTERN_MAIN_NPC_SHADOW","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……그때 코치가 추천한 스나이퍼, 결국 누구였더라?","JPN":"……あの時コーチが紹介したスナイパー、結局誰だっけ？","ENG":"...Who was that sniper that Coach recommended back then?","TWN":"……那時候教練推薦的狙擊手，最後是誰來著？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"미나가 우리 마지막 멤버였으니까, 역시 처음에는 스나이퍼 포지션으로 배정됐었나?","JPN":"ミナが最後のメンバーだったから、やっぱり初めはスナイパーに指定されたんだっけ？","ENG":"Since Mina ended up being our last member, maybe she was originally assigned the sniper role?","TWN":"米娜是我們最後一個成員，所以一開始被分配到狙擊手的位置了嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그런데… 걔 성격 상, 스나이퍼를 맡을 것 같지는 않은데……?","JPN":"でも……あいつの性格上、スナイパーをやるとは思えない……","ENG":"But... knowing her personality, I just can't see her being a sniper...?","TWN":"但是……以她的性格，應該不會擔任狙擊手吧……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아 몰라……!","JPN":"ああもう……！","ENG":"Ugh, whatever...!","TWN":"啊，不知道……！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"다 끝난 일인데, 이제 와서 그딴 게 뭐가 중요해?","JPN":"全部終わったことなのに、今更何が重要なんだよ？","ENG":"It's all in the past, so why does any of this even matter now?","TWN":"都已經結束了，現在說那些還有什麼意義？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"인간의 언어. 말이 통해도 소통할 수는 없다.","JPN":"人間ノ言語。言葉ガ通ジテモ疎通ハデキナイ。","ENG":"Human language. Can understand. But cannot communicate.","TWN":"人類的語言，即使能說話，也無法溝通。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE"},{"id":"L9_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"대화. 역시나 비효율적인 정보 공유 방법.","JPN":"会話。ヤハリ非効率的ナ情報共有手段。","ENG":"Conversation. Inefficient way to share information.","TWN":"對話，果然是低效的資訊共用方式。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"이쪽이 빠르다.","JPN":"コッチガ早イ。","ENG":"This is faster.","TWN":"這邊比較快。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"크윽, 이 자식……!","JPN":"くっ、この野郎……！","ENG":"Ugh, damn it...!","TWN":"呃，你這傢伙……！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"다짜고짜 공격하다니!","JPN":"いきなり攻撃しやがって！","ENG":"Attacking out of nowhere?!","TWN":"不問青紅皂白就開始攻擊！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"게다가 이 위력…! 전에 봤을 때보다 훨씬 강해진 것 같은데……?","JPN":"しかもこの威力……！　前よりずっと強くなってる……？","ENG":"And this power...! He's way stronger than last time...!","TWN":"而且這威力……！好像比之前看到的更強了……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"원한다. 네가 가진 정보.","JPN":"欲シイ。オマエノ情報。","ENG":"I want it. Information that you have.","TWN":"我想要你掌握的資訊。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_05"},{"id":"L18_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"순순히 내게 먹혀라. 녹색 머리 여자.","JPN":"大人シクオレニ食ワレロ。緑ノ髪ノ女。","ENG":"Let me eat you. Green-haired woman.","TWN":"乖乖地被我吃掉吧，綠色頭髮的女人。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"정보를 내놓는 거다.","JPN":"情報ヲヨコセ。","ENG":"Hand over the information.","TWN":"交出資訊。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"시끄러워! 어딜 개수작이야……!","JPN":"ふざけるな！　何がよこせだ！","ENG":"Shut up! You think I'm just gonna sit here and let you try that...?!","TWN":"吵死了！你在搞什麼鬼……！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"가스 폭발……?","JPN":"ガス爆発……？","ENG":"A gas explosion...?","TWN":"煤氣爆炸……？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어차피 엔간한 탄환으로는 네 갑피에 흠집도 못 내겠지……!","JPN":"どうせ普通の弾丸じゃあんたの甲皮にかすり傷も負わせられないだろ……！","ENG":"Yeah, regular bullets wouldn't even scratch that armor of yours...!","TWN":"反正一般的子彈根本無法在你的甲殼上留下任何痕跡……！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그럴 바엔, 차라리 도망칠 시간이라도 벌겠다 이거야!","JPN":"いっそのこと逃げる時間を稼いだほうがマシだってな！","ENG":"Might as well use it to buy myself some time to run!","TWN":"那還不如爭取時間逃跑呢！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"상황 판단. 빠르군.","JPN":"状況判断。早イ。","ENG":"Quick thinking. Impressive.","TWN":"判斷形勢，很快啊。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 소용없다.","JPN":"シカシ無駄ダ。","ENG":"But pointless.","TWN":"但是沒用的。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"여자를 쫓아라.","JPN":"女ヲ追イカケロ。","ENG":"Chase the girl.","TWN":"追那個女人。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_45"},{"id":"L36_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"쫓아서 산 채로 데려와라.","JPN":"追イカケテ、生キタママ捕ラエロ。","ENG":"Bring her back alive.","TWN":"追上去，活捉她。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>샤레이드 도시 관리국에서 알립니다.</color>","JPN":"<color=#ffd34c>シャレード都市管理局からお知らせいたします。</color>","ENG":"<color=#ffd34c>Attention. This is Charade's City Management.</color>","TWN":"<color=#ffd34c>查雷德城市管理局通知。</color>"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재, 도심 일부 지역에 침식파 밀도가 급격히 상승하고 있습니다.</color>","JPN":"<color=#ffd34c>現在、都市中心部の一部の地域において侵食波密度が急激に上昇しています。</color>","ENG":"<color=#ffd34c>Currently, Corruption ray levels are rapidly rising in some areas of the city.</color>","TWN":"<color=#ffd34c>目前，市中心部分地區的侵蝕波密度正在急劇上升。</color>"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재 추세로 볼때, 곧 급성 침식 경보가 발령될 예정입니다.</color>","JPN":"<color=#ffd34c>現在の状況から、まもなく急性侵食警報が発令される見込みです。</color>","ENG":"<color=#ffd34c>Given the current trend, an acute Corruption alert may be issued soon.</color>","TWN":"<color=#ffd34c>根據目前預測的趨勢，發佈急性侵蝕警報。</color>"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"도심 한 가운데서 급성 침식 경보?","JPN":"都市のど真ん中で急性侵食警報？","ENG":"An acute Corruption alert... right in the middle of the city?","TWN":"市中心發生急性侵蝕警報？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이건 설마……?","JPN":"これってまさか……？","ENG":"This can't be...","TWN":"這難道是……？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"잠깐, 전에도 이런 적이 있었어! 그땐 분명히……!","JPN":"待って、前もこんなことがあったわ！　あの時は確か……！","ENG":"Wait, this happened before! I remember this...!","TWN":"等等，以前也有過這種情況！那時候明明是……！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"펠리세트, 스키너……!","JPN":"フェリセット、スキナー……！","ENG":"Félicette, Skinner...!","TWN":"費莉塞特，史金納……！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"여기서 노닥거리고 있을 때가 아니야! 이 밑에 침식체가 쫙 깔렸다고!","JPN":"ここで遊んでる場合じゃない！　この下は侵食体がうようよしてるんだ！","ENG":"We don't have time to stand around! There are C.O.s swarming right beneath us!","TWN":"現在不是在這裡閒逛的時候！下面全是侵蝕體！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"당장 도망쳐야 해!","JPN":"今すぐ逃げないと！","ENG":"We have to run!","TWN":"要趕快逃！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그, 그렇지만 여긴 옥상이잖아? 어디로 도망치라는 거야?","JPN":"で、でもここは屋上でしょう？　どこへ逃げるの？","ENG":"B-but we're on the roof! Where are we supposed to run to?","TWN":"那，那可是這裡是樓頂啊？讓我往哪裡逃啊？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이유는 모르겠지만… 아무튼 그 망할 침식체가 나랑 꼬맹이를 노리는 것 같거든?","JPN":"理由はわからないけど……あのクソ侵食体、私とおこちゃまを狙ってるみたい。","ENG":"I don't know why, but the damn C.O. seems to be targeting me and the kid!","TWN":"雖然不知道原因……總之那個該死的侵蝕體好像盯上了我和小鬼？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그러니까 스키너, 너는 할배 챙겨서 옆 건물 옥상으로 넘어가!","JPN":"だからスキナー、あんたはジジイと一緒に隣のビルの屋上に移動するんだ！","ENG":"So, Skinner, take the old chap and jump over to the next rooftop!","TWN":"所以史金納，你帶著老頭去旁邊的樓頂！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"우리가 여기서 시간을 끌어 볼 테니까.","JPN":"私たちがここで時間を稼いでみる！","ENG":"We'll hold them off here as long as we can.","TWN":"我們會在這裡拖延時間。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"아, 알았어……!","JPN":"わ、わかった……！","ENG":"Ah, okay...!","TWN":"知、知道了……！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"뭘 어쩌려고 그래요, 라이카?","JPN":"どうするつもりなの、ライカ？","ENG":"What are you thinking, Laika?","TWN":"你打算做什麼，萊卡？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"카운터도 없고, 우리가 지금 가지고 있는 탄약으로는 침식체를 당해낼 수 없다고요.","JPN":"カウンターもいないし、今手持ちの弾薬じゃ侵食体に勝てる見込みがないわ。","ENG":"We don't have any Counters, and the ammo we've got won't be enough to take on those C.O.s.","TWN":"沒有制裁者，我們現在的彈藥也無法對抗侵蝕體。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"낸들아냐? 그래도 우리가 짬이 있는데, 스키너랑 꽐라 된 할아범보단 나을 거 아니야.","JPN":"知るかよ。でもスキナーと酔っ払いのジジイよりは経験のある私たちのほうがマシだろ。","ENG":"No idea. But we've at least got some experience. Better than Skinner and that drunk old chap, right?","TWN":"我怎麼知道？不過我們也有經驗，總比史金納和那個醉醺醺的老頭強吧。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"여차하면 네 비장의 수단도 있고.","JPN":"いざとなったら、あんたには切り札もあるし。","ENG":"Worst case, you still have the ace up your sleeve.","TWN":"發生意外時你也有秘密武器。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"도심 한가운데서 그걸 썼다간, 리그 우승 상품을 전부 배상금으로 써야 할 걸요?","JPN":"都心でそれを使ったら、リーグの賞金をぜーんぶ賠償に使うことになるわよ？","ENG":"If I use that in the middle of the city, we'll end up blowing our entire league prize money on damages!","TWN":"如果在市中心使用那個，聯賽冠軍的獎金可能全都要用來賠償了喔？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"여기서는 안 돼요. 적어도 최대한 사람이 없는 공터를 찾아야 해요.","JPN":"ここはまずいわ。せめて人気のない更地じゃないと。","ENG":"Not here. We need to find a clear, empty area. Somewhere with no civilians around.","TWN":"這裡不行。至少要找到一個儘量沒有人的空地。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"쳇, 하여간 주인 닮아서 까다롭긴…….","JPN":"ちっ、主に似て面倒くさいやつだな。","ENG":"Tch, you're so damn picky...","TWN":"嘖，真是像主人一樣難伺候……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어쨌든 뛸 준비해, 꼬맹이","JPN":"とにかく、走るから準備しろよ。","ENG":"Anyway, get ready to move, kid.","TWN":"總之，準備好跑吧，小鬼"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"녀석들을 최대한 사람이 없는 곳으로 끌어내는 거야!","JPN":"なるべく人のいない場所に、やつらをおびき寄せるんだ！","ENG":"We're leading them somewhere with no people!","TWN":"儘量把他們引到沒有人的地方去！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};